import { useState } from "react";

import MainBtns from "../Components/Buttons/MainBtns";
import InputForm from "../Components/Input/InputForm";
import AdditionalInformation from "../Components/TextComponents/AdditionalInformation";
import TitleText from "../Components/TextComponents/TitleText";

import config from "../config.json"
import axios from "axios";

function RegisterPage() {

  const [email,setEmail] = useState();
  const [password, setPass] = useState();

  const Request = () =>{
    axios.post(config.BaseURL +"/auth/login", {
      email,
      password
    },{withCredentials: true})
  }
  return (
    <>
      <TitleText TextOnTitle={"Регистрация по эл. почте"} MarginOnBot={"150px"} LetterSpacing={"3px"}/>
      <InputForm TextPlaceholder="Адрес электронной почты"/>
      <InputForm TextPlaceholder={"Отображаемое имя"}/>
      <InputForm TextPlaceholder={"Пароль"}/>
      <MainBtns Style={"purple-btn"} Text={"Продолжить"} Width={"400px"} Height={68} FontSize={"30px"} FontWeight={"100"} Padding={0} MarginTop={"auto"}  />
      <AdditionalInformation FirstText={"Есть аккаунт?"} SecondText={"Войти"} NavigateTo={"/join/login"}/>
    </>
  );
}

export default RegisterPage;
